parameters.functionCode:
const agents = [
  {
    id: 'cliente-alpha',
    displayName: 'Cliente Alpha',
    briefing: 'Trader iniciante testando sinais por screenshot em gráficos cripto de 1 minuto.'
  },
  {
    id: 'cliente-beta',
    displayName: 'Cliente Beta',
    briefing: 'Scalper experiente avaliando ajustes finos de buffer, stop e RR.'
  },
  {
    id: 'cliente-gamma',
    displayName: 'Cliente Gamma',
    briefing: 'Usuário focado em automatização e testes embutidos no navegador.'
  }
];

const responsiveAi = {
  id: 'scalp-ia',
  displayName: 'IA Responsiva',
  tone: 'Objetiva, com respostas curtas e ações práticas.'
};

const knowledge = {
  resumo: 'Interface estática para sugerir operações de scalp a partir de screenshots, com modos Manual e Auto.',
  passos: [
    'Abrir index.html no navegador desktop.',
    'Carregar/colar screenshot do gráfico.',
    'Escolher modo Manual (marca topo/fundo/último preço) ou Auto (beta).',
    'Ajustar buffer, stop e risco/retorno.',
    'Executar Analisar e usar Testes para validar regras.'
  ],
  destaques: [
    'Upload, arrastar/soltar e colagem direta de imagens.',
    'Modo Demo sem necessidade de screenshot.',
    'Overlay com níveis de topo, fundo, entrada, stop e alvo.',
    'Testes embutidos cobrindo regras estritas (> / <) e inclusivas (≥ / ≤).'
  ],
  manualVsAuto: 'No Manual o usuário marca topo, fundo e último preço; o Auto (beta) estima borda direita e recomenda ESPERA se falhar.'
};

const incoming = $json;
const agentId = (incoming.agent || '').toLowerCase();
const message = (incoming.message || '').toLowerCase();

const selectedAgent = agents.find(a => a.id === agentId) || agents[0];

let reply = '';

const includesAny = (parts) => parts.some(part => message.includes(part));

if (includesAny(['como usar', 'passo', 'instru'])) {
  reply = `Sou ${responsiveAi.displayName}. Para usar a ferramenta: ${knowledge.passos.map((p, idx) => `${idx + 1}. ${p}`).join(' ')}`;
} else if (includesAny(['funciona', 'recurso', 'feature', 'capacidade'])) {
  reply = `Principais recursos: ${knowledge.destaques.join(' | ')}`;
} else if (includesAny(['manual', 'auto', 'beta'])) {
  reply = knowledge.manualVsAuto;
} else if (includesAny(['teste', 'valid'])) {
  reply = 'Clique em Testes no painel e veja cenários de rompimento estrito e inclusivo direto no navegador.';
} else if (includesAny(['buffer', 'stop', 'rr', 'alvo'])) {
  reply = 'O painel permite ajustar buffer de rompimento, stop em pixels e RR (alvo = stop × RR) antes de analisar.';
} else {
  reply = `${knowledge.resumo} Compartilhe dúvidas específicas para orientar o próximo passo.`;
}

return [{
  json: {
    agentAccount: selectedAgent,
    aiAccount: responsiveAi,
    originalMessage: incoming.message || '',
    agentResponse: reply,
    knowledgeBase: knowledge
  }
}];
